import React from "react";

const navItems = [
  { id: "dashboard", label: "Dashboard", dot: "#22c55e", icon: "⬡" },
  { id: "needs", label: "Community Needs", dot: "#ef4444", icon: "◉" },
  { id: "volunteers", label: "Volunteers", dot: "#3b82f6", icon: "◈" },
  { id: "map", label: "Map View", dot: "#8b5cf6", icon: "◎" },
  { id: "matching", label: "Smart Match", dot: "#f59e0b", icon: "◆" },
  { id: "submit-need", label: "Submit Need", dot: "#10b981", icon: "+" },
  { id: "add-volunteer", label: "Add Volunteer", dot: "#06b6d4", icon: "+" },
];

export default function Sidebar({ page, setPage, urgentCount, availableCount }) {
  return (
    <nav className="sidebar">
      <div className="logo">
        <h1>ReliefLink</h1>
        <p>Smart Resource Coordination</p>
      </div>
      <div className="nav-section">
        <div className="nav-label">Navigation</div>
        {navItems.map((item) => (
          <button
            key={item.id}
            className={`nav-item ${page === item.id ? "active" : ""}`}
            onClick={() => setPage(item.id)}
          >
            <span className="nav-dot" style={{ background: item.dot }} />
            {item.label}
          </button>
        ))}
      </div>
      <div className="sidebar-footer">
        {urgentCount > 0 && (
          <div style={{ color: "#dc2626", fontWeight: 600, marginBottom: 4, fontSize: 12 }}>
            ⚠ {urgentCount} urgent needs
          </div>
        )}
        <div style={{ fontSize: 11, color: "#94a3b8" }}>{availableCount} volunteers available</div>
      </div>
    </nav>
  );
}
